  1	import React, { FC, useEffect } from 'react';
  2	import { useLocation } from 'react-router-dom-v5-compat';
  3	
  4	import { V1VirtualMachine, V1VirtualMachineInstance } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import HardwareDevicesTable from '@kubevirt-utils/components/HardwareDevices/HardwareDevicesTable';
  6	import HardwareDeviceTitle from '@kubevirt-utils/components/HardwareDevices/HardwareDeviceTitle';
  7	import HardwareDevicesModal from '@kubevirt-utils/components/HardwareDevices/modal/HardwareDevicesModal';
  8	import { HARDWARE_DEVICE_TYPE } from '@kubevirt-utils/components/HardwareDevices/utils/constants';
  9	import { useModal } from '@kubevirt-utils/components/ModalProvider/ModalProvider';
 10	import SearchItem from '@kubevirt-utils/components/SearchItem/SearchItem';
 11	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 12	import { useToggle } from '@kubevirt-utils/hooks/useToggle';
 13	import { getGPUDevices, getHostDevices } from '@kubevirt-utils/resources/vm';
 14	import { Bullseye, Divider, ExpandableSection, Flex, Grid, GridItem } from '@patternfly/react-core';
 15	
 16	import { getSearchItemsIds } from '../../search/utils/utils';
 17	import { expandURLHash, getDetailsTabHardwareIds } from '../../utils/search';
 18	import { updateHardwareDevices } from '../utils/utils';
 19	
 20	type DetailsSectionHardwareProps = {
 21	  onSubmit?: (type: HARDWARE_DEVICE_TYPE, updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine>;
 22	  vm: V1VirtualMachine;
 23	  vmi?: V1VirtualMachineInstance;
 24	};
 25	
 26	const DetailsSectionHardware: FC<DetailsSectionHardwareProps> = ({
 27	  onSubmit: onSubmitProp,
 28	  vm,
 29	  vmi,
 30	}) => {
 31	  const { t } = useKubevirtTranslation();
 32	  const { createModal } = useModal();
 33	  const location = useLocation();
 34	  const [isExpanded, setIsExpanded] = useToggle('hardware-devices');
 35	  const onSubmit = onSubmitProp || updateHardwareDevices;
 36	  const hostDevices = getHostDevices(vm);
 37	  const gpus = getGPUDevices(vm);
 38	
 39	  useEffect(() => {
 40	    expandURLHash(getSearchItemsIds(getDetailsTabHardwareIds(vm)), location?.hash, setIsExpanded);
 41	  }, [location?.hash, vm]);
 42	
 43	  const onEditHostDevices = () => {
 44	    createModal(({ isOpen, onClose }) => (
 45	      <HardwareDevicesModal
 46	        btnText={t('Add Host device')}
 47	        headerText={t('Host devices')}
 48	        initialDevices={hostDevices}
 49	        isOpen={isOpen}
 50	        onClose={onClose}
 51	        onSubmit={(updatedVM) => onSubmit(HARDWARE_DEVICE_TYPE.HOST_DEVICES, updatedVM)}
 52	        type={HARDWARE_DEVICE_TYPE.HOST_DEVICES}
 53	        vm={vm}
 54	        vmi={vmi}
 55	      />
 56	    ));
 57	  };
 58	
 59	  const onEditGPU = () => {
 60	    createModal(({ isOpen, onClose }) => (
 61	      <HardwareDevicesModal
 62	        btnText={t('Add GPU device')}
 63	        headerText={t('GPU devices')}
 64	        initialDevices={gpus}
 65	        isOpen={isOpen}
 66	        onClose={onClose}
 67	        onSubmit={(updatedVM) => onSubmit(HARDWARE_DEVICE_TYPE.GPUS, updatedVM)}
 68	        type={HARDWARE_DEVICE_TYPE.GPUS}
 69	        vm={vm}
 70	        vmi={vmi}
 71	      />
 72	    ));
 73	  };
 74	
 75	  return (
 76	    <ExpandableSection
 77	      toggleContent={
 78	        <SearchItem id="hardware-devices">
 79	          {t('Hardware devices ({{devices}})', {
 80	            devices: gpus?.length + hostDevices?.length || 0,
 81	          })}
 82	        </SearchItem>
 83	      }
 84	      isExpanded={isExpanded}
 85	      isIndented
 86	      onToggle={(_event, val) => setIsExpanded(val)}
 87	    >
 88	      <Grid>
 89	        <GridItem span={4}>
 90	          <HardwareDeviceTitle canEdit onClick={onEditGPU} title={t('GPU devices')} />
 91	          <HardwareDevicesTable devices={gpus} />
 92	        </GridItem>
 93	
 94	        <GridItem span={1}>
 95	          <Bullseye>
 96	            <Flex className={'DetailsSection-divider__height'}>
 97	              <Divider orientation={{ default: 'vertical' }} />
 98	            </Flex>
 99	          </Bullseye>
100	        </GridItem>
101	
102	        <GridItem span={4}>
103	          <HardwareDeviceTitle canEdit onClick={onEditHostDevices} title={t('Host devices')} />
104	          <HardwareDevicesTable devices={hostDevices} />
105	        </GridItem>
106	      </Grid>
107	    </ExpandableSection>
108	  );
109	};
110	
111	export default DetailsSectionHardware;

